import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import SiteNavbar from '../components/layout/SiteNavbar';
import SiteFooter from '../components/layout/SiteFooter';
import AdminLogin from '../components/auth/AdminLogin';
import CustomerAuthCard from '../components/auth/CustomerAuthCard';
import { loginAdmin, loginCustomer } from '../services/api';
import { useAuth } from '../context/AuthContext';

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [adminLoading, setAdminLoading] = useState(false);
  const [customerLoading, setCustomerLoading] = useState(false);

  const handleAdminLogin = async (payload) => {
    setAdminLoading(true);
    try {
      const data = await loginAdmin(payload);
      login(data.token, data.user);
      navigate('/dashboard/admin', { replace: true });
    } catch (error) {
      alert(error.response?.data?.message || 'Unable to login as admin');
    } finally {
      setAdminLoading(false);
    }
  };

  const handleCustomerLogin = async (payload) => {
    setCustomerLoading(true);
    try {
      const data = await loginCustomer(payload);
      login(data.token, data.user);
      navigate('/dashboard/customer', { replace: true });
    } catch (error) {
      alert(error.response?.data?.message || 'Invalid customer credentials');
    } finally {
      setCustomerLoading(false);
    }
  };

  return (
    <div className="d-flex flex-column min-vh-100">
      <SiteNavbar />
      <main className="flex-grow-1 py-5 bg-light">
        <div className="container">
          <div className="text-center mb-5">
            <p className="text-uppercase small text-muted mb-1">Secure login</p>
            <h1 className="fw-bold">Choose your portal</h1>
            <p className="text-muted">
              Admins manage nationwide operations. Customers can track, book, and manage their services.
            </p>
          </div>
          <div className="row g-4">
            <div className="col-lg-6">
              <CustomerAuthCard onSubmit={handleCustomerLogin} isLoading={customerLoading} />
              <p className="text-center mt-3 small text-muted">
                New to Dakkhana? <Link to="/register">Create an account</Link>
              </p>
            </div>
            <div className="col-lg-6">
              <AdminLogin onSubmit={handleAdminLogin} isLoading={adminLoading} />
              <p className="small text-center text-muted mt-3">
                For branch managers & HQ users. Need access? Raise a ticket with Circle Office.
              </p>
            </div>
          </div>
        </div>
      </main>
      <SiteFooter />
    </div>
  );
}
